#include <bits/stdc++.h>
using namespace std;
int main(){
    int a,b,sum=1;
    scanf("%d%d",&a,&b);
    for(int i=1;i<=b;i++){
        sum*=a;
        sum%=7;
    }
    switch(sum){
        case 0:
            cout<<"Sunday";
            break;
        case 1:
            cout<<"Monday";
            break;
        case 2:
            cout<<"Tuesday";
            break;
        case 3:
            cout<<"Wednesday";
            break;
        case 4:
            cout<<"Thursday";
            break;
        case 5:
            cout<<"Friday";
            break;
        case 6:
            cout<<"Saturday";
            break;
    }
}
